def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        if ratio > 3:
            priorities[i] = 3000 + (ratio - 3)**2 * 250
            if ratio > 5:
                priorities[i] += (ratio - 5) * 500
        elif 2 < ratio <= 3:
            priorities[i] = 1000 + (ratio - 2)**3 * 150
        elif 1.2 < ratio <= 2:
            priorities[i] = 600 + (ratio - 1.2) * 80
        elif np.isclose(ratio, 1, atol=1e-8):
            priorities[i] = 200
        else:
            score = 0
            for j in range(1, 12):
                temp = ((capacity - item) ** j) / (capacity ** (j+1))
                if temp < 0.03:
                    score += temp * 120 / j
                elif 0.03 <= temp < 0.15:
                    score += np.log1p(temp * 100)/ (j**1.5) * 25
                else:
                    score += np.sqrt(temp) * 15 / (j**2)
            if score < 0.03:
                priorities[i] = score * 25 + (capacity - item) * 0.01
            elif 0.03 <= score < 0.25:
                priorities[i] = 2 / (score + 0.7) - (item / (capacity + 1)) * 0.05
            else:
                adjustment = 0
                for k in range(1, 6):
                    adj_term = ((item / (capacity + k)) ** (k*0.5)) * 12 / (k + 2)
                    if k % 2 == 0:
                        adjustment += adj_term
                    else:
                        adjustment -= adj_term * 0.5
                priorities[i] = 1.5 / (score + 1.2) + adjustment
        leftover_ratio = (capacity - item) / capacity
        if leftover_ratio < 0.15 and leftover_ratio > 0:
            priorities[i] += (0.15 - leftover_ratio) * 50
        if item >= 0.85 * capacity:
            priorities[i] *= 0.85
        if i % 3 == 0:
            priorities[i] += 2 / (capacity + 2)
            if capacity % 2 == 1:
                priorities[i] += np.sin(capacity) * 0.1
        elif i % 3 == 1:
            priorities[i] -= 1.5 / (capacity + 3)
            for m in range(1, 4):
                priorities[i] += ((m * item) % capacity) * 0.0001
        else:
            priorities[i] += np.log1p(capacity) * 0.05 - np.sqrt(item) * 0.02
    return priorities
